import React, { useState, useEffect } from "react";
import ab1 from "../assets/ab-hl-1.jpg";
import ab2 from "../assets/ab-hl-2.jpeg";
import ab3 from "../assets/ab-hl-3.jpg";
import ab4 from "../assets/ab-hl-4.jpg";

function About() {
  const images = [ab1, ab2, ab3, ab4];
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 4000); // slide every 4s
    return () => clearInterval(interval);
  }, []);

  return (
    <section
      id="about-section"
      style={{
        position: "relative",
        height: "450px",
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "center",
        margin: "60px auto",
        borderRadius: "15px",
        overflow: "hidden",
        maxWidth: "1100px",
        boxShadow: "0 8px 20px rgba(0,0,0,0.2)",
      }}
    >
      {/* Background Slideshow */}
      <img
        src={images[currentIndex]}
        alt="About Slide"
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          objectFit: "cover",
          top: 0,
          left: 0,
          transition: "opacity 1s ease-in-out",
          zIndex: -1,
        }}
      />

      {/* Transparent Info Box */}
      <div
        style={{
          width: "100%",
          padding: "25px 30px",
          backgroundColor: "rgba(255, 255, 255, 0.85)",
          textAlign: "center",
          backdropFilter: "blur(6px)",
        }}
      >
        <h2
          style={{
            marginBottom: "12px",
            fontSize: "26px",
            fontWeight: "700",
            color: "#007bff",
          }}
        >
          HEALink
        </h2>
        <p
          style={{
            fontSize: "16px",
            color: "#333",
            lineHeight: "1.6",
            maxWidth: "900px",
            margin: "0 auto",
          }}
        >
          HEALink was started with a vision to connect people with better
          healthcare solutions. We provide pathology, medicine, consultancy, and
          blood bank services to make healthcare accessible and reliable for
          everyone. Our mission is to ensure that every individual gets the care
          they need with trust and convenience.
        </p>
      </div>
    </section>
  );
}

export default About;
